import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const n="/assets/01-thumbnail.BhfFjeMI.png",p="/assets/02-add-proxmox-repo.BOw6W7cE.png",o="/assets/03-apt-install-proxmox.Iqgf5M8d.png",r="/assets/04-postfix-local-only.JfwYXgEw.png",l="/assets/05-postfix-mail-name.DHnD6Cmb.png",h="/assets/06-ssl-warning.VRjAwYE4.png",d="/assets/07-login.DOHG6zVq.png",c="/assets/08-invalid-subscription.DKPiNC-X.png",g="/assets/09-main-menu.CBqsTlxQ.png",C=JSON.parse(`{"title":"Installing Proxmox on a Raspberry Pi (It's FOSS)","description":"Notes on Installing Proxmox on a Raspberry Pi (It's FOSS).","frontmatter":{"title":"Installing Proxmox on a Raspberry Pi (It's FOSS)","description":"Notes on Installing Proxmox on a Raspberry Pi (It's FOSS)."},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/install-proxmox-on-a-raspberry-pi/itsfoss-install-proxmox-raspberry-pi.md","filePath":"microcontrollers-and-socs/raspberry-pi/install-proxmox-on-a-raspberry-pi/itsfoss-install-proxmox-raspberry-pi.md"}`),k={name:"microcontrollers-and-socs/raspberry-pi/install-proxmox-on-a-raspberry-pi/itsfoss-install-proxmox-raspberry-pi.md"};function u(m,s,b,y,F,x){return i(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="installing-proxmox-on-a-raspberry-pi-to-run-virtual-machines-on-it" tabindex="-1">Installing Proxmox on a Raspberry Pi to run Virtual Machines on it <a class="header-anchor" href="#installing-proxmox-on-a-raspberry-pi-to-run-virtual-machines-on-it" aria-label="Permalink to &quot;Installing Proxmox on a Raspberry Pi to run Virtual Machines on it&quot;">​</a></h1><p><img src="'+n+`" alt="Installing Proxmox on Raspberry Pi"></p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://itsfoss.com/install-proxmox-raspberry-pi/" target="_blank" rel="noreferrer">https://itsfoss.com/install-proxmox-raspberry-pi/</a></li><li>Imported: 2026-06-11</li><li>Images: 9 downloaded to <code>./assets/itsfoss-install-proxmox-raspberry-pi/</code> (hero, repo setup, install, Postfix, SSL warning, login, subscription notice, dashboard)</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>Proxmox Virtual Environment (VE) is an open-source platform for managing virtual machines and containers through a web interface. Proxmox is <strong>not officially supported on Raspberry Pi</strong>, but third-party ARM repositories make experimental installs possible.</p><p>This guide targets lightweight experimentation, not heavy VM workloads. A Raspberry Pi 4 or 5 with ample RAM is recommended.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Raspberry Pi 4 or 5 (8 GB RAM recommended)</li><li>MicroSD card (Class 10 or better)</li><li><strong>64-bit Raspberry Pi OS Lite (Bookworm)</strong></li><li>Power supply and Ethernet cable (wired preferred)</li></ul><h3 id="step-1-start-with-a-clean-slate" tabindex="-1">Step 1: Start with a clean slate <a class="header-anchor" href="#step-1-start-with-a-clean-slate" aria-label="Permalink to &quot;Step 1: Start with a clean slate&quot;">​</a></h3><p>Use a <strong>fresh</strong> Raspberry Pi OS Lite 64-bit (Bookworm) install. Older or cluttered systems can cause package dependency errors during install.</p><p>Flash the image with Raspberry Pi Imager.</p><h3 id="step-2-update-and-upgrade" tabindex="-1">Step 2: Update and upgrade <a class="header-anchor" href="#step-2-update-and-upgrade" aria-label="Permalink to &quot;Step 2: Update and upgrade&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>Install curl if missing:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span></span></code></pre></div><h3 id="step-3-set-a-static-ip-address" tabindex="-1">Step 3: Set a static IP address <a class="header-anchor" href="#step-3-set-a-static-ip-address" aria-label="Permalink to &quot;Step 3: Set a static IP address&quot;">​</a></h3><p>Proxmox needs a stable IP. Prefer a <strong>DHCP reservation</strong> on your router.</p><p>Alternatively, edit <code>/etc/dhcpcd.conf</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/dhcpcd.conf</span></span></code></pre></div><p>Add:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>interface [INTERFACE]</span></span>
<span class="line"><span>static ip_address=[STATIC IP ADDRESS YOU WANT]/24</span></span>
<span class="line"><span>static routers=[ROUTER IP]</span></span>
<span class="line"><span>static domain_name_servers=[DNS IP]</span></span></code></pre></div><p>Reboot and verify:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> now</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span></span></code></pre></div><h3 id="step-4-modify-etc-hosts" tabindex="-1">Step 4: Modify <code>/etc/hosts</code> <a class="header-anchor" href="#step-4-modify-etc-hosts" aria-label="Permalink to &quot;Step 4: Modify \`/etc/hosts\`&quot;">​</a></h3><p>Map the hostname to the Pi’s static IP:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/hosts</span></span></code></pre></div><p>Change:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>127.0.1.1    raspberrypi</span></span></code></pre></div><p>To (example):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>192.168.1.9    raspberrypi</span></span></code></pre></div><h3 id="step-5-set-the-root-password" tabindex="-1">Step 5: Set the root password <a class="header-anchor" href="#step-5-set-the-root-password" aria-label="Permalink to &quot;Step 5: Set the root password&quot;">​</a></h3><p>Proxmox web login uses <code>root</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> passwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span></span></code></pre></div><h3 id="step-6-add-the-gpg-key" tabindex="-1">Step 6: Add the GPG key <a class="header-anchor" href="#step-6-add-the-gpg-key" aria-label="Permalink to &quot;Step 6: Add the GPG key&quot;">​</a></h3><p>Third-party ARM packages are served from the apqa.cn mirror:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://mirrors.apqa.cn/proxmox/debian/pveport.gpg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/share/keyrings/pveport.gpg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span></code></pre></div><h3 id="step-7-add-the-repository" tabindex="-1">Step 7: Add the repository <a class="header-anchor" href="#step-7-add-the-repository" aria-label="Permalink to &quot;Step 7: Add the repository&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;deb [arch=arm64 signed-by=/usr/share/keyrings/pveport.gpg] https://mirrors.apqa.cn/proxmox/debian/pve bookworm port&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apt/sources.list.d/pveport.list</span></span></code></pre></div><p><img src="`+p+'" alt="Adding the Proxmox repository"></p><h3 id="step-8-update-the-package-list" tabindex="-1">Step 8: Update the package list <a class="header-anchor" href="#step-8-update-the-package-list" aria-label="Permalink to &quot;Step 8: Update the package list&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><h3 id="step-9-install-proxmox" tabindex="-1">Step 9: Install Proxmox <a class="header-anchor" href="#step-9-install-proxmox" aria-label="Permalink to &quot;Step 9: Install Proxmox&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proxmox-ve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> postfix</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open-iscsi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ifupdown2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pve-edk2-firmware-aarch64</span></span></code></pre></div><p>Package roles:</p><ul><li><strong>proxmox-ve</strong> — core Proxmox server and web UI</li><li><strong>postfix</strong> — local mail for alerts (choose <strong>Local only</strong> if unsure)</li><li><strong>open-iscsi</strong> — network storage support</li><li><strong>ifupdown2</strong> — network interface management for bridges</li><li><strong>pve-edk2-firmware-aarch64</strong> — ARM64 VM firmware</li></ul><p><img src="'+o+'" alt="Installing Proxmox and dependencies"></p><p>During Postfix setup:</p><p><img src="'+r+'" alt="Postfix — Local only"></p><p>Use the default system mail name if unsure:</p><p><img src="'+l+'" alt="Postfix system mail name"></p><h3 id="step-10-access-the-proxmox-web-interface" tabindex="-1">Step 10: Access the Proxmox web interface <a class="header-anchor" href="#step-10-access-the-proxmox-web-interface" aria-label="Permalink to &quot;Step 10: Access the Proxmox web interface&quot;">​</a></h3><p>Open:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://&lt;IPADDRESS&gt;:8006</span></span></code></pre></div><p>Expect a self-signed certificate warning:</p><p><img src="'+h+'" alt="Proxmox SSL warning in browser"></p><p>Log in as <strong><code>root</code></strong> with the password set in Step 5:</p><p><img src="'+d+'" alt="Proxmox login page"></p><p>Dismiss the invalid subscription notice (free/community use):</p><p><img src="'+c+'" alt="Proxmox invalid subscription prompt"></p><p>The dashboard shows CPU, memory, and storage stats. Use <strong>Create VM</strong> to start a new virtual machine:</p><p><img src="'+g+'" alt="Proxmox main dashboard"></p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Proxmox on Pi is <strong>experimental</strong> — use a clean <strong>64-bit Bookworm Lite</strong> image.</li><li>Set a <strong>static IP</strong> and align <code>/etc/hosts</code> with that address before install.</li><li>This guide uses the <strong>apqa.cn</strong> <code>pveport</code> repository and GPG key (<code>pveport.gpg</code>).</li><li>Web UI: <code>https://&lt;pi-ip&gt;:8006</code> as user <strong><code>root</code></strong>; ignore the subscription warning on first login.</li><li>Keep VM workloads light; Pi 4/5 with 8 GB RAM is the practical hardware target.</li></ul>',64)])])}const P=a(k,[["render",u]]);export{C as __pageData,P as default};
